            sb.append(" encoding=\"").append(encoding).append("\"");
        }
        for (Attribute attr : attributes) {
            String key = attr.getKey();
            if (!key.equals("version") && !key.equals("encoding")) {
                sb.append(" ").append(key).append("=\"").append(attr.getValue()).append("\"");
